Script.Source:
            import sailpoint.object.Filter;
            import sailpoint.object.ManagedAttribute;
            import sailpoint.object.QueryOptions;
            import sailpoint.object.Identity;
            import sailpoint.object.IdentityEntitlement;
            import java.util.Iterator;
            import java.util.List;
            import sailpoint.object.Application;

            if(actionType!=null && appname != null && actionType.equals("Remove Entitlements") && null != employee){
            Identity identityObject= context.getObject(Identity.class, employee);
            if(identityObject!=null){
            QueryOptions qoEntUser = new QueryOptions();
            Filter f1= Filter.eq("identity", identityObject);
            qoEntUser.addFilter(f1);
            if(appname != null){
            Filter filter = Filter.eq("application.name",appname);
            qoEntUser.addFilter(filter);
            }
            Iterator identityEntitlements = context.search(IdentityEntitlement.class,qoEntUser);
            List allEntsBelongingToUser = new ArrayList();
            while(identityEntitlements.hasNext()){
            IdentityEntitlement idEnt = (IdentityEntitlement) identityEntitlements.next();
            allEntsBelongingToUser.add(idEnt.getValue());
            }
            sailpoint.tools.Util.flushIterator(identityEntitlements);
            return allEntsBelongingToUser;
            }
            }
            else if(appname != null){
            List allEntitlementsList = new ArrayList();
            Application application = context.getObjectByName(Application.class, appname); 
            QueryOptions qo = new QueryOptions();
            Filter filter = Filter.eq("application.name",appname);
            qo.add(filter);
            List allEntFinalList = new ArrayList();
            allEntitlementsList = context.getObjects(ManagedAttribute.class, qo);

            for(ManagedAttribute mgAttr:allEntitlementsList){
            String entName = mgAttr.getValue();
            String attrName = mgAttr.getAttribute();
            entName = attrName+":"+entName;
            allEntFinalList.add(entName);
            }
            return allEntFinalList;

            }

