          if(null != emp){
          if(idAttribute != null){       
          String uniqueIdAttr = GeneralUtils.loadCustomMap(customUpdateAttrKey, opsconCustomObjectName).get(idAttribute);
          if(emp.getAttribute(uniqueIdAttr) != null){
          if(idAttribute.equalsIgnoreCase("Inactive")){
          String attrValue = "";
