          if(bValue){
          attrValue = "true";
          }else{
          attrValue = "false";
          }
          return attrValue;
          }
          else {
          String attrValue = emp.getAttribute(uniqueIdAttr);
          return attrValue;

          }
          }else
          {
          return "This attribute is empty on identity.";
          }
          }
          }
          }

